21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const PROCESSING_FEE = 5;
31	const BLOCK_OF_THREE_PREMIUM = 60;
32	
33	export function quote(
34	  _customer: Customer,
35	  items: Item[],
36	  _options: QuoteOptions = {},
37	): QuoteResult {
38	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
39	    counts[item.type] = (counts[item.type] ?? 0) + 1;
40	    return counts;
41	  }, {});
42	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
43	    (sum, [type, count]) =>
44	      sum +
45	      (count === 3
46	        ? BLOCK_OF_THREE_PREMIUM
47	        : count * basePremiumByType[type]),
48	    0,
49	  );
50	  const basePremium =
51	    items.length === 1 && items[0].cursed
52	      ? baseWithoutSurcharges * 1.5
53	      : items.length === 1 && (items[0].enchantment ?? 0) >= 5
54	        ? baseWithoutSurcharges * 1.3
55	        : baseWithoutSurcharges;
56	  const premium = items.length === 0 ? PROCESSING_FEE : 0;
57	  return { basePremium, premium };
58	}
