const singleItemSurchargeFactor =
  items.length === 1 ? surchargeFactorFor(items[0]) : 1;
const basePremium = baseWithoutSurcharges * singleItemSurchargeFactor;

const PROCESSING_FEE = 5;
const BLOCK_OF_THREE_PREMIUM = 60;

function surchargeFactorFor(item: Item): number {
  if (item.cursed) return 1.5;
  if ((item.enchantment ?? 0) >= 5) return 1.3;
  return 1;
}
